INSERT INTO tenants(id,name,slug) VALUES('10000000-0000-4000-8000-000000000001','Nailsoft Demo','nailsoft-demo');
INSERT INTO branches(id,tenant_id,name,code,timezone) VALUES('20000000-0000-4000-8000-000000000001','10000000-0000-4000-8000-000000000001','Quận 1','Q1','Asia/Ho_Chi_Minh'),('20000000-0000-4000-8000-000000000002','10000000-0000-4000-8000-000000000001','Thủ Đức','TD','Asia/Ho_Chi_Minh');
INSERT INTO users(id,origin_tenant_id,email,display_name) SELECT ('30000000-0000-4000-8000-'||lpad(n::text,12,'0'))::uuid,'10000000-0000-4000-8000-000000000001',CASE WHEN n=1 THEN 'owner@example.test' ELSE 'staff'||n||'@example.test' END,CASE WHEN n=1 THEN 'Owner' WHEN n=2 THEN 'Manager' WHEN n<5 THEN 'Receptionist '||(n-2) ELSE 'Technician '||(n-4) END FROM generate_series(1,12)n;
INSERT INTO tenant_memberships(id,tenant_id,user_id,status,joined_at) SELECT ('90000000-0000-4000-8000-'||lpad(n::text,12,'0'))::uuid,'10000000-0000-4000-8000-000000000001',('30000000-0000-4000-8000-'||lpad(n::text,12,'0'))::uuid,'ACTIVE',now() FROM generate_series(1,12)n;
INSERT INTO membership_roles(membership_id,role) SELECT ('90000000-0000-4000-8000-'||lpad(n::text,12,'0'))::uuid,CASE WHEN n=1 THEN 'SALON_OWNER' WHEN n=2 THEN 'BRANCH_MANAGER' WHEN n<5 THEN 'RECEPTIONIST' ELSE 'NAIL_TECHNICIAN' END FROM generate_series(1,12)n;
INSERT INTO membership_branches(membership_id,tenant_id,branch_id) SELECT ('90000000-0000-4000-8000-'||lpad(n::text,12,'0'))::uuid,'10000000-0000-4000-8000-000000000001','20000000-0000-4000-8000-000000000001' FROM generate_series(2,12)n;
INSERT INTO tenant_settings(tenant_id) VALUES('10000000-0000-4000-8000-000000000001');
INSERT INTO branch_settings(tenant_id,branch_id) SELECT tenant_id,id FROM branches;
INSERT INTO business_hours(tenant_id,branch_id,day_of_week,open_time,close_time,is_closed) SELECT tenant_id,id,day,CASE WHEN day=0 THEN NULL ELSE time '09:00' END,CASE WHEN day=0 THEN NULL ELSE time '20:00' END,day=0 FROM branches CROSS JOIN generate_series(0,6) day;
INSERT INTO service_categories(id,tenant_id,name_json) SELECT ('40000000-0000-4000-8000-'||lpad(n::text,12,'0'))::uuid,'10000000-0000-4000-8000-000000000001',jsonb_build_object('vi-VN','Danh mục '||n,'en-US','Category '||n) FROM generate_series(1,6)n;
INSERT INTO services(id,tenant_id,category_id,code,name_json,duration_minutes,base_price_minor) SELECT ('50000000-0000-4000-8000-'||lpad(n::text,12,'0'))::uuid,'10000000-0000-4000-8000-000000000001',('40000000-0000-4000-8000-'||lpad((((n-1)%6)+1)::text,12,'0'))::uuid,'SVC-'||n,jsonb_build_object('vi-VN','Dịch vụ '||n,'en-US','Service '||n),60,100000+n*10000 FROM generate_series(1,30)n;
INSERT INTO customers(id,tenant_id,display_name,phone_normalized) SELECT ('60000000-0000-4000-8000-'||lpad(n::text,12,'0'))::uuid,'10000000-0000-4000-8000-000000000001','Khách '||n,'+8490000'||lpad(n::text,4,'0') FROM generate_series(1,20)n;
INSERT INTO appointments(id,tenant_id,branch_id,customer_id,status,start_at,end_at) SELECT ('70000000-0000-4000-8000-'||lpad(n::text,12,'0'))::uuid,'10000000-0000-4000-8000-000000000001','20000000-0000-4000-8000-000000000001',('60000000-0000-4000-8000-'||lpad((((n-1)%20)+1)::text,12,'0'))::uuid,(ARRAY['CONFIRMED','CHECKED_IN','COMPLETED','NO_SHOW'])[((n-1)%4)+1],timestamptz '2026-07-13 09:00+07'+(n||' hours')::interval,timestamptz '2026-07-13 10:00+07'+(n||' hours')::interval FROM generate_series(1,40)n;
INSERT INTO products(tenant_id,sku,name,kind) SELECT '10000000-0000-4000-8000-000000000001','SKU-'||n,'Sản phẩm '||n,CASE WHEN n<6 THEN 'CONSUMABLE' ELSE 'RETAIL' END FROM generate_series(1,10)n;
INSERT INTO vouchers(tenant_id,code,kind,usage_limit) VALUES('10000000-0000-4000-8000-000000000001','WELCOME10','PERCENTAGE',100),('10000000-0000-4000-8000-000000000001','NEW50K','FIXED_AMOUNT',50),('10000000-0000-4000-8000-000000000001','ADDONFREE','FREE_ADDON',25);
INSERT INTO loyalty_programs(tenant_id,name,status) VALUES('10000000-0000-4000-8000-000000000001','Rewards','ACTIVE');
INSERT INTO commission_rules(tenant_id,name,rule_json,status) VALUES('10000000-0000-4000-8000-000000000001','Service 10%','{"value":10}','ACTIVE'),('10000000-0000-4000-8000-000000000001','Retail 5%','{"value":5}','ACTIVE'); COMMIT;
